import{_ as s,o as n,c as e,ag as t}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Enums","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/enums.md","filePath":"archive/reference/enums.md"}'),p={name:"archive/reference/enums.md"};function i(l,a,c,o,r,d){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="enums" tabindex="-1">Enums <a class="header-anchor" href="#enums" aria-label="Permalink to &quot;Enums&quot;">​</a></h1><p><strong>Core Language Specification</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented</p><p>Enums (Enumerations) allow a value to be one of several variants. Vex enums are <strong>Algebraic Data Types</strong>, meaning they can carry data.</p><hr><h2 id="_1-definition" tabindex="-1">1. Definition <a class="header-anchor" href="#_1-definition" aria-label="Permalink to &quot;1. Definition&quot;">​</a></h2><h3 id="c-style-enums" tabindex="-1">C-Style Enums <a class="header-anchor" href="#c-style-enums" aria-label="Permalink to &quot;C-Style Enums&quot;">​</a></h3><p>Simple list of values. (Default discriminant starts at 0).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enum Status {</span></span>
<span class="line"><span>    Active,</span></span>
<span class="line"><span>    Inactive,</span></span>
<span class="line"><span>    Pending,</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="explicit-discriminants" tabindex="-1">Explicit Discriminants <a class="header-anchor" href="#explicit-discriminants" aria-label="Permalink to &quot;Explicit Discriminants&quot;">​</a></h3><p>You can assign specific integer values.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enum HttpStatus {</span></span>
<span class="line"><span>    Ok = 200,</span></span>
<span class="line"><span>    NotFound = 404,</span></span>
<span class="line"><span>    Error = 500,</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="_2-variants-with-data" tabindex="-1">2. Variants with Data <a class="header-anchor" href="#_2-variants-with-data" aria-label="Permalink to &quot;2. Variants with Data&quot;">​</a></h2><p>Enums can act as Tagged Unions.</p><h3 id="tuple-variants" tabindex="-1">Tuple Variants <a class="header-anchor" href="#tuple-variants" aria-label="Permalink to &quot;Tuple Variants&quot;">​</a></h3><p>Variants can hold positional data.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enum IpAddr {</span></span>
<span class="line"><span>    V4(u8, u8, u8, u8),</span></span>
<span class="line"><span>    V6(string),</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let localhost = IpAddr.V4(127, 0, 0, 1);</span></span></code></pre></div><h3 id="generic-enums" tabindex="-1">Generic Enums <a class="header-anchor" href="#generic-enums" aria-label="Permalink to &quot;Generic Enums&quot;">​</a></h3><p>Enums can be generic (like <code>Option&lt;T&gt;</code>).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enum BoxedValue&lt;T&gt; {</span></span>
<span class="line"><span>    Raw(T),</span></span>
<span class="line"><span>    Boxed(Box&lt;T&gt;),</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="_3-built-in-core-enums" tabindex="-1">3. Built-in Core Enums <a class="header-anchor" href="#_3-built-in-core-enums" aria-label="Permalink to &quot;3. Built-in Core Enums&quot;">​</a></h2><p>Vex optimizes two specific enums at the compiler level for null safety and error handling.</p><h3 id="option-t" tabindex="-1">Option&lt;T&gt; <a class="header-anchor" href="#option-t" aria-label="Permalink to &quot;Option\\&lt;T&gt;&quot;">​</a></h3><p>Replaces <code>null</code>.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enum Option&lt;T&gt; {</span></span>
<span class="line"><span>    Some(T),</span></span>
<span class="line"><span>    None,</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="result-t-e" tabindex="-1">Result&lt;T, E&gt; <a class="header-anchor" href="#result-t-e" aria-label="Permalink to &quot;Result\\&lt;T, E&gt;&quot;">​</a></h3><p>Replaces exceptions.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enum Result&lt;T, E&gt; {</span></span>
<span class="line"><span>    Ok(T),</span></span>
<span class="line"><span>    Err(E),</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>These are treated specially by the compiler. <code>match</code> on them can be optimized, and memory layout is compressed (e.g. <code>Option&lt;&amp;T&gt;</code> fits in a single pointer, with 0 representing <code>None</code>).</p></div><hr><h2 id="_4-pattern-matching" tabindex="-1">4. Pattern Matching <a class="header-anchor" href="#_4-pattern-matching" aria-label="Permalink to &quot;4. Pattern Matching&quot;">​</a></h2><p>Use <code>match</code> to extract data.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let msg = IpAddr.V4(127, 0, 0, 1);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>match msg {</span></span>
<span class="line"><span>    IpAddr.V4(a, b, c, d) =&gt; {</span></span>
<span class="line"><span>        (f&quot;IPv4: {a}.{b}.{c}.{d}&quot;);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    IpAddr.V6(s) =&gt; {</span></span>
<span class="line"><span>        (f&quot;IPv6: {s}&quot;);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="exhaustiveness" tabindex="-1">Exhaustiveness <a class="header-anchor" href="#exhaustiveness" aria-label="Permalink to &quot;Exhaustiveness&quot;">​</a></h3><p>All variants must be covered, or use <code>_</code> (wildcard).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>match status {</span></span>
<span class="line"><span>    Status.Active =&gt; { ... }</span></span>
<span class="line"><span>    _ =&gt; { (&quot;Other status&quot;); }</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="_5-methods" tabindex="-1">5. Methods <a class="header-anchor" href="#_5-methods" aria-label="Permalink to &quot;5. Methods&quot;">​</a></h2><p>Like structs, enums can have methods defined via External (UFCS) syntax.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn (self: &amp;IpAddr) is_loopback(): bool {</span></span>
<span class="line"><span>    match *self {</span></span>
<span class="line"><span>        IpAddr.V4(127, 0, 0, 1) =&gt; return true;</span></span>
<span class="line"><span>        _ =&gt; return false;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,41)])])}const m=s(p,[["render",i]]);export{u as __pageData,m as default};
